mapper.select:
select id, user_id, listening_id, line_number, status, updated_at
from listening_feedback
where user_id = #{userId}
  and listening_id = #{listeningId}
order by line_number asc

select id, user_id, listening_id, line_number, status, updated_at
from listening_feedback
where user_id = #{userId}
  and listening_id = #{listeningId}
  and line_number = #{lineNumber}

mapper.update:
update listening_feedback
set status = #{status},
    updated_at = #{updatedAt}
where id = #{id}
